// Źródła: złote standardy Alterbake (Drive) + ZS Planowanie Produkcji (docs/baza-wiedzy)
window.AB_WIEDZA = {
reguly: [{"id": "sc-001", "kategoria": "mrozenie", "warunek": "Plan zawiera entremets/monoporcje z insertem (crémeux, żel owocowy) na dzień D", "rada": "Zaplanuj insert na dzień D-1 lub wcześniej: mroź szybko i cienko (małe kryształy = zachowana tekstura), montaż i glazura świeżo w dniu D. Mrożenie insertów to standard, nie wyjątek.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. VIII, IX); Złoty Standard Cukiernictwa v2026-06-13"}, {"id": "sc-002", "kategoria": "mrozenie", "warunek": "Komponent ma trafić do zamrażarki", "rada": "Mrożą się dobrze: musy, bawarki, crémeux, inserty żelatynowe, biszkopty i blaty, surowe kruche i laminat, ganache, skorupki makaroników (niezanadziane), puste skorupy choux. Mroź w cienkich warstwach, jeśli nie masz blast freezera.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. VIII)"}, {"id": "sc-003", "kategoria": "mrozenie", "warunek": "Ktoś chce zamrozić bitą śmietanę, żel agarowy, glazurę lub świeże wodniste owoce", "rada": "Nie mroź: bita śmietana niestabilizowana się oddziela, żele agarowe puszczają wodę (synereza), świeże wodniste owoce miękną, niektóre glazury pękają — glazury najpierw przetestuj na próbce.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. VIII)"}, {"id": "sc-004", "kategoria": "mrozenie", "warunek": "Wyjmowanie mrożonego komponentu do użycia", "rada": "Rozmrażaj w chłodni (+4°C), nigdy w temperaturze pokojowej — równomiernie i bez przerwania łańcucha chłodniczego (CCP4). Entremets rozmrażaj w chłodni już po glazurowaniu na zamrożono.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. VIII, IX)"}, {"id": "sc-005", "kategoria": "mrozenie", "warunek": "Cokolwiek wkładane do zamrażarki", "rada": "Etykieta obowiązkowa: nazwa + data + termin, wydawanie wg FEFO, wpis do rejestru PÓŁPRODUKTY_CUKIER. Maksymalny czas przechowywania mrożonego nie jest ustalony w standardach — do kalibracji WSP.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. VIII); Kompendium Część X Organizacja Cukierni v2026-06-17"}, {"id": "sc-006", "kategoria": "mrozenie", "warunek": "Produkcja tart / spodów kruchych", "rada": "Surowe kruche mrozi się doskonale (dysk lub wyłożona forma) — rób partie na zapas. Wyłożoną formę zamroź 15 min przed wypiekiem: zero kurczenia boków.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. III)"}, {"id": "sc-007", "kategoria": "mrozenie", "warunek": "Produkcja makaroników", "rada": "Skorupki mroź tylko niezanadziane. Nadziane makaroniki dojrzewają 24 h w chłodzie przed sprzedażą (wyrównanie wilgoci i smaku) — wlicz tę dobę do planu.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. IV)"}, {"id": "sc-008", "kategoria": "chlodzenie", "warunek": "Ugotowano krem pâtissière", "rada": "Rozlej cienko, przykryj folią na styk i schłódź natychmiast — nie trzymaj w strefie 10–60°C. Trwałość chłodnicza wg standardu 24–48 h (firmowy CCP: max 3°C / 2 dni). Nadziewaj tuż przed sprzedażą.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. V)"}, {"id": "sc-009", "kategoria": "chlodzenie", "warunek": "Przegląd chłodni / przyjęcie komponentów", "rada": "Chłodnia to CCP, nie magazyn: każdy komponent opisany i datowany, układ wg FEFO, kontrola temperatur przez funkcję Chłodnia. To jednocześnie HACCP i kontrola straty.", "zrodlo": "Złoty Standard Cukiernictwa v2026-06-13; Kompendium Część X Organizacja Cukierni v2026-06-17"}, {"id": "sc-010", "kategoria": "chlodzenie", "warunek": "Przechowywanie bez, makaroników lub wyrobów czekoladowych", "rada": "Trzymaj z dala od chłodni i pary: beza jest higroskopijna (mięknie w godziny), a czekolada łapie sugar bloom od kondensacji. Czekolada: 16–18°C, sucho, szczelnie.", "zrodlo": "Złoty Standard Bezy v2026-06-13; Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. VII); Cukiernictwo Część XIII Pakowanie i Transport"}, {"id": "sc-011", "kategoria": "chlodzenie", "warunek": "Planowana produkcja croissantów / laminatu", "rada": "Laminuj w 14–16°C z chłodnią między każdym obrotem; détrempe retarduj przez noc (smak + logistyka). Sprawdź wolne miejsce w chłodni PRZED zaplanowaniem laminatu — to jego wąskie gardło.", "zrodlo": "Złoty Standard Ciast Wzbogaconych v2026-06-13"}, {"id": "sc-012", "kategoria": "chlodzenie", "warunek": "Planowana produkcja brioche / babki maślanej", "rada": "Zimna fermentacja 4–24 h przy 4–6°C jest obowiązkowa — zaplanuj zagniecenie dzień wcześniej, formowanie na zimno następnego dnia. TDT max ~26°C przy wyrabianiu.", "zrodlo": "Złoty Standard Ciast Wzbogaconych v2026-06-13"}, {"id": "sc-013", "kategoria": "chlodzenie", "warunek": "Produkcja ciasta kruchego", "rada": "Odpoczynek w chłodni (4–6°C) min. 1–2 h po zagnieceniu i ponownie po wyłożeniu formy — inaczej spód się kurczy. Wlicz te odpoczynki do harmonogramu dnia.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. III)"}, {"id": "sc-014", "kategoria": "chlodzenie", "warunek": "Wyroby z kremem idą na witrynę lub do dostawy", "rada": "Witryna chłodzona i transport to przedłużenie CCP4, nie osobny temat. Torby izotermiczne obowiązkowe dla wszystkiego chłodzonego. Zmierz raz czas transportu poza chłodnią i wpisz go jako twardy limit.", "zrodlo": "Cukiernictwo Część XIII Pakowanie i Transport"}, {"id": "sc-015", "kategoria": "chlodzenie", "warunek": "Drożdżówki z masą serową w planie", "rada": "Masę serową przygotuj wcześniej i trzymaj w chłodni aż do nadziewania — twaróg + jaja to krótki łańcuch chłodniczy. Masa musi być gęsta (budyń/mąka ziemniaczana ~20 g na 500 g twarogu), inaczej wypłynie.", "zrodlo": "Instrukcja Ciasto Słodkie Drożdżowe v2026-06-13"}, {"id": "sc-016", "kategoria": "kolejnosc", "warunek": "Układanie planu dnia cukierni", "rada": "Komponenty (biszkopty, kremy, inserty, ganache) z wyprzedzeniem — dzień wcześniej lub rano; montaż, glazura i wykończenie świeżo, ekspedycja falami pod 15:00–20:00. To rozkłada szczyt pracy i podnosi powtarzalność.", "zrodlo": "Złoty Standard Cukiernictwa v2026-06-13; Kompendium Część X Organizacja Cukierni v2026-06-17"}, {"id": "sc-017", "kategoria": "kolejnosc", "warunek": "Koniec dnia produkcyjnego", "rada": "Domknięcie dnia = ustawienie jutra: inserty zamrożone, komponenty opisane i datowane, chłodnia wg FEFO, plan na jutro gotowy. Eliminuje poranne decyzje wymagające kierowniczki.", "zrodlo": "Złoty Standard Cukiernictwa v2026-06-13; Kompendium Część X Organizacja Cukierni v2026-06-17"}, {"id": "sc-018", "kategoria": "kolejnosc", "warunek": "Start dnia / przed każdym montażem", "rada": "Mise en place totalne: wszystko odważone, opisane, w zasięgu ręki, plan dnia na ekranie. W cukierni ważniejsze niż w piekarni — montaż wymaga wielu komponentów w jednym oknie czasowym. Odprawa 5 min: kto pilnuje której funkcji.", "zrodlo": "Złoty Standard Cukiernictwa v2026-06-13; Cukiernictwo Część X Kompetencje v2026-07-06"}, {"id": "sc-019", "kategoria": "kolejnosc", "warunek": "Produkty z kremem (ptysie, eklery, tarty) w planie sprzedaży wieczornej", "rada": "Skorupy piecz z wyprzedzeniem i przechowuj suche; nadziewaj kremem tuż przed sprzedażą, falami pod godziny ruchu. Ogranicza to stratę i ryzyko CCP5.", "zrodlo": "Złoty Standard Ciast Wzbogaconych v2026-06-13; Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. II, V)"}, {"id": "sc-020", "kategoria": "kolejnosc", "warunek": "Wyrabianie ciasta drożdżowego słodkiego lub brioche", "rada": "Najpierw pełne rozwinięcie glutenu (test błony), dopiero potem masło — partiami. Masło dodane wcześniej = ciasto ciężkie i zbite. Przy >18% cukru obowiązkowo kolejność fazowa: gluten wstępny → sól → cukier partiami → masło.", "zrodlo": "Złoty Standard Ciast Wzbogaconych v2026-06-13; Instrukcja Ciasto Słodkie Drożdżowe v2026-06-13"}, {"id": "sc-021", "kategoria": "kolejnosc", "warunek": "W planie tygodnia jest viennoiserie i ciasto francuskie", "rada": "Planuj laminaty razem — wspólne wąskie gardło (chłodnia 14–16°C, czas obrotów). Jeden cykl tourage tnij pod kilka produktów, a skrawki (rognures) wałkuj na palmiery/spody — zero strat.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. III)"}, {"id": "sc-022", "kategoria": "kolejnosc", "warunek": "Montaż entremets", "rada": "Montuj à l'envers (od góry, w formie, na mrożonych komponentach): croustillant na dole produktu, potem biszkopt z ponczem, insert mrożony, mus, glazura na koniec. Insert zawsze zamrożony osobno przed montażem.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. IX)"}, {"id": "sc-023", "kategoria": "kolejnosc", "warunek": "Przekazanie półproduktu między etapami (handoff)", "rada": "Każdy handoff to 10 sekund kontroli wg wzorca — półprodukt nie idzie dalej, póki nie spełnia wzorca (schłodzony, opisany, zmierzony; montaż: wysokość i warstwy; wykończenie: połysk i równość). Tańsze niż reklamacja.", "zrodlo": "Kompendium Część X Organizacja Cukierni v2026-06-17"}, {"id": "sc-024", "kategoria": "kolejnosc", "warunek": "Ciasto drożdżowe na jutro rano / model wieczorny", "rada": "Wybierz fermentację zimną w chłodni przez noc zamiast ciepłej (45–60 min przy 28–30°C): lepszy smak i wygodna logistyka — formujesz prosto z chłodni.", "zrodlo": "Instrukcja Ciasto Słodkie Drożdżowe v2026-06-13"}, {"id": "sc-025", "kategoria": "kolejnosc", "warunek": "Beza włoska w planie", "rada": "Zgraj czasy: zacznij ubijać białka, gdy syrop osiągnie ~110°C — będą na miękkich szczytach dokładnie przy 118–121°C syropu. Wlewaj cienką strużką po ściance, nigdy na trzepaczkę.", "zrodlo": "Złoty Standard Bezy v2026-06-13"}, {"id": "sc-026", "kategoria": "delegacja", "warunek": "Przydzielanie zadań pomocy (Julia, Natalia) — zadania wykonawcze", "rada": "Pomocnik może samodzielnie: ważyć wg fiche technique, etykietować i pilnować FIFO/FEFO, mrozić inserty wg instrukcji czasowej, sprzątać (clean as you go), transportować. To stała, pełnoprawna rola — nie każdy musi dążyć do Samodzielnego.", "zrodlo": "Cukiernictwo Część X Kompetencje v2026-07-06"}, {"id": "sc-027", "kategoria": "delegacja", "warunek": "Przydzielanie zadań wymagających osądu sensorycznego", "rada": "Nigdy nie deleguj pomocnikowi: oceny gotowości kremu/bezy/temperowania, korekty receptury, interpretacji CCP5 przy wartości granicznej, montażu finalnego z oceną estetyczną, kalibracji sprzętu. Te zadania planuj na osobę min. poziomu Samodzielny.", "zrodlo": "Cukiernictwo Część X Kompetencje v2026-07-06"}, {"id": "sc-028", "kategoria": "delegacja", "warunek": "Nowa osoba w zespole (pierwsze 6 tygodni)", "rada": "Junior pracuje wg fiche pod obserwacją 0–6 tyg.; ścieżka: BHP+CCP5 → kremy → masy/spody → bezy/cukier → czekolada/żelifikacja → montaż. Awans na Samodzielnego od 6–8 tyg. po checkliście (m.in. krem bez podpowiedzi, diagnoza 1 wady, granica CCP5 na pamięć).", "zrodlo": "Cukiernictwo Część X Kompetencje v2026-07-06"}, {"id": "sc-029", "kategoria": "delegacja", "warunek": "Układanie obsady dnia", "rada": "Każda z czterech funkcji (Komponenty, Montaż, Chłodnia+etykiety, Wykończenie+ekspedycja) ma w danym dniu jednego właściciela — nie 'wszyscy wszystkiego'. Docelowo każdy umie min. dwie funkcje (rotacja = odporność).", "zrodlo": "Kompendium Część X Organizacja Cukierni v2026-06-17"}, {"id": "sc-030", "kategoria": "delegacja", "warunek": "Odchylenie CCP, dryf receptury, brak surowca lub reklamacja", "rada": "Eskalacja zawsze do lead (Oliwia) — przy ryzyku sanitarnym nie zgaduj samodzielnie. Lead może zdecydować zdalnie: zdjęcie przekroju + parametry w wiadomości zastępują obecność przy stole.", "zrodlo": "Kompendium Część X Organizacja Cukierni v2026-06-17"}, {"id": "sc-031", "kategoria": "delegacja", "warunek": "Szkolenie dyscypliny termometru w zespole", "rada": "Crème anglaise (okno 82–84°C) to najlepszy trening sondy dla nowej osoby — przydzielaj ją jako ćwiczenie pod okiem Samodzielnego/Mentora. Temperowanie: dla zespołu wybieraj szczepienie lub Mycryo, nie tablage.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. V, VII)"}, {"id": "sc-032", "kategoria": "haccp", "warunek": "Gotowanie każdego kremu (pâtissière i pokrewne)", "rada": "CCP5 jest nienegocjowalne: obróbka ≥85°C przez ≥1 min, zweryfikowana termometrem, potem szybkie schłodzenie. Pâtissière gotuj 1–2 min od wrzenia — inaczej amylaza z żółtka nie zostanie zdezaktywowana i krem zrzednie po schłodzeniu.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. V); Cukiernictwo Część X Kompetencje v2026-07-06"}, {"id": "sc-033", "kategoria": "haccp", "warunek": "Gotowanie anglaise / crémeux", "rada": "Trzymaj okno 82–84°C ('à la nappe') — powyżej ~85–86°C żółtko zetnie się w grudki. Sonda obowiązkowa. Ratunek przy zwarzeniu: natychmiast blender + sito + zimna kąpiel.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. V)"}, {"id": "sc-034", "kategoria": "haccp", "warunek": "Dekoracja lub krem bez obróbki termicznej (surowe białko)", "rada": "Do wyrobów bez pieczenia używaj wyłącznie bezy włoskiej (syrop 118–121°C pasteryzuje białko). Szwajcarska (55–60°C) jest tylko częściowo zabezpieczona, francuska bezpieczna dopiero po wysuszeniu/upieczeniu — ryzyko Salmonelli.", "zrodlo": "Złoty Standard Bezy v2026-06-13"}, {"id": "sc-035", "kategoria": "haccp", "warunek": "Praca z gorącym cukrem / karmelem / syropem do bezy", "rada": "BHP twarde: cukier 120–180°C przylega do skóry i oparza głęboko — nigdy nie dotykaj ani nie smakuj z garnka, trzymaj wodę z lodem w zasięgu ręki, uważaj na pryski przy deglasowaniu. Najwyższe ryzyko urazu w cukierni.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. VI)"}, {"id": "sc-036", "kategoria": "haccp", "warunek": "Planowanie produkcji z alergenami (orzechy, mak, sezam, czekolada)", "rada": "Alergeny wg matrycy 1169/2011: gluten, mleko, jaja, orzechy, soja (lecytyna w czekoladzie). Osobne narzędzia, clean as you go — alergen i strata lubią bałagan. Oznacz wyroby i pilnuj kontaminacji krzyżowej.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. IX); Instrukcja Ciasto Słodkie Drożdżowe v2026-06-13"}, {"id": "sc-037", "kategoria": "haccp", "warunek": "Produkcja curd (cytrynowy itp.)", "rada": "Grzej do ~78–83°C (kwas obniża próg koagulacji) — to zarazem pasteryzacja w procesie. Kwas + cukier dają dłuższą trwałość niż kremy mleczne — dobry kandydat na trwalszy komponent. Alergeny: jajo, mleko.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. V)"}, {"id": "sc-038", "kategoria": "haccp", "warunek": "Kontrola dnia — kto odpowiada za CCP", "rada": "CCP5 odpowiada każdy, kto gotuje krem; CCP4 (łańcuch chłodniczy, FEFO) — właściciel funkcji Chłodnia. Zapisy w DZIENNIKU; odchylenie zawsze eskalowane do lead.", "zrodlo": "Kompendium Część X Organizacja Cukierni v2026-06-17"}, {"id": "sc-039", "kategoria": "piec", "warunek": "Wypiek choux, biszkoptów lub laminatu", "rada": "Nie otwieraj pieca w fazie wzrostu — spadek pary/temperatury = zapadnięcie. Choux: start 200–220°C, potem 170–180°C (na konwekcji Bongard bywa stałe ~180°C); dopiecz do suchych ścianek, ewentualnie dosusz przy uchylonym piecu.", "zrodlo": "Złoty Standard Ciast Wzbogaconych v2026-06-13"}, {"id": "sc-040", "kategoria": "piec", "warunek": "Wypiek wyrobów słodkich (cukier, jajko w cieście)", "rada": "Cukier brązowieje szybciej, niż ciasto się piecze — brązowienie ≠ upieczenie. Kontroluj wnętrze, nie kolor; gdy wierzch ciemnieje a środek surowy: obniż temperaturę lub przykryj i piecz dłużej.", "zrodlo": "Złoty Standard Ciast Wzbogaconych v2026-06-13; Instrukcja Ciasto Słodkie Drożdżowe v2026-06-13"}, {"id": "sc-041", "kategoria": "piec", "warunek": "Suszenie bez / Pavlovej w planie dnia", "rada": "Beza francuska SUSZY się, nie piecze: 90–110°C przez 1–3 h, studzenie w wyłączonym piecu — to długi blok pieca, planuj poza oknem innych wypieków. W wilgotne dni susz dłużej.", "zrodlo": "Złoty Standard Bezy v2026-06-13"}, {"id": "sc-042", "kategoria": "piec", "warunek": "Rozrost croissantów / laminatu przed wypiekiem", "rada": "Rozrost końcowy 24–26°C (wysoka wilgotność, ~2–3 h), zawsze poniżej ~30°C topnienia masła — inaczej masło wycieknie i struktura będzie chlebowa. Piecz 175–200°C na decku z parą na starcie.", "zrodlo": "Złoty Standard Ciast Wzbogaconych v2026-06-13"}, {"id": "sc-043", "kategoria": "piec", "warunek": "Dobór pieca do produktu", "rada": "IBIS GT MAXI (deck, para impulsowa, dolna grzałka): viennoiserie, ciasto francuskie, tarty (równy spód), wyższe torty. Bongard Krystal+ (konwekcja): choux, makaroniki (symetryczna stopka), cienkie blaty biszkoptowe.", "zrodlo": "Złoty Standard Ciast Wzbogaconych v2026-06-13; Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. III, IV)"}, {"id": "sc-044", "kategoria": "piec", "warunek": "Wypiek makaroników", "rada": "145–155°C, 12–16 min, podwójna blacha chroni spód; przed piecem suszenie skorupki 20–40 min do matowej błonki (palec nie klei) — bez tego wierzch pęknie zamiast stopki. Obróć blachę przy nierównym grzaniu.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. IV)"}, {"id": "sc-045", "kategoria": "piec", "warunek": "Nowy produkt lub zmiana parametrów pieca", "rada": "Wszystkie temperatury i czasy w standardach to wartości startowe. Pierwszy wsad traktuj jako próbny: zanotuj temperaturę i czas, które dały dobry wynik, wpisz na twardo i trzymaj się ich.", "zrodlo": "Instrukcja Ciasto Słodkie Drożdżowe v2026-06-13; Kompendium Cukiernictwa Rozszerzone v2026-06-17"}, {"id": "sc-046", "kategoria": "piec", "warunek": "Temperowanie czekolady w planie dnia (zwłaszcza latem)", "rada": "Pomieszczenie musi mieć 18–20°C — powyżej temperowanie i zastyganie są zawodne; latem planuj czekoladę w oknie porannym. Krzywe: gorzka 45–50/27–28/31–32°C, mleczna 45/27/29–30°C, biała 45/26/28–29°C. Test: zastyga w 3–5 min z połyskiem.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. VII)"}, {"id": "sc-047", "kategoria": "jakosc", "warunek": "Każde stanowisko, każdy dzień", "rada": "Waga (0,1 g do małych naważek) i termometr sondowy to narzędzia pierwszego wyboru — cukiernictwo to chemia: ±1°C w temperowaniu, ±5°C w kremie zmieniają wynik. Waż w gramach, nie 'na oko'.", "zrodlo": "Złoty Standard Cukiernictwa v2026-06-13"}, {"id": "sc-048", "kategoria": "jakosc", "warunek": "Codziennie po produkcji", "rada": "Degustuj własny produkt codziennie — dryf receptury masz złapać Ty, nie klient. Odchylenia notuj w DZIENNIKU ze zdjęciem przekroju i parametrami; sukcesów nie notujemy, odchylenia tak.", "zrodlo": "Złoty Standard Cukiernictwa v2026-06-13; Cukiernictwo Część X Kompetencje v2026-07-06"}, {"id": "sc-049", "kategoria": "jakosc", "warunek": "Łączenie mas o różnych temperaturach (mus, bawarka, krem maślany, ganache)", "rada": "Wyrównuj temperatury baz: baza za ciepła topi pianę, za zimna z żelatyną żeluje w grudki. Krem maślany: masło i baza ~22–25°C; SMBC — masło gdy beza ostygnie do ~25°C, partiami. Ganache łącz w 35–40°C i emulguj od środka blenderem.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. V)"}, {"id": "sc-050", "kategoria": "jakosc", "warunek": "Dozowanie żelatyny / praca z hydrokoloidami", "rada": "Żelatynę licz w gramach na litr, nie w listkach: ~6–10 g/L miękki żel/mus, ~15–20 g/L jędrny żel (wartości startowe). Nie gotuj żelatyny. Świeży ananas/kiwi/papaja rozkładają żelatynę — sparz owoc.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. VIII)"}, {"id": "sc-051", "kategoria": "jakosc", "warunek": "Glazurowanie / wykończenie entremets", "rada": "Glazura lustrzana: lej w 30–35°C na całkowicie zamrożony produkt (matowa = produkt nie był dość zimny; spływa = za ciepła; smugi = za zimna). Aksamit: natrysk ~40–45°C, czekolada+masło kakaowe ~1:1, też na zamrożone. Blenduj bez napowietrzania.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. VIII, IX)"}, {"id": "sc-052", "kategoria": "jakosc", "warunek": "Nowy deser wchodzi do karty", "rada": "Sprawdź listą kontrolną sześć osi balansu: słodycz – kwas – gorycz – tłuszcz – tekstura – temperatura. Za słodkie = brak kwasu; płaskie = brak kontrastu tekstur. Karta produktu: zdjęcie wzorca + profil smaku 1–5 — jeden wzorzec, jeden smak, niezależnie kto robi.", "zrodlo": "Złoty Standard Cukiernictwa v2026-06-13; Kompendium Część X Organizacja Cukierni v2026-06-17"}, {"id": "sc-053", "kategoria": "jakosc", "warunek": "Ubijanie bezy (dowolnej)", "rada": "Naczynia idealnie czyste i beztłuszczowe, zero żółtka; białka w temp. pokojowej; cukier stopniowo po spienieniu; ubijaj do sztywnych błyszczących szczytów — ani sekundy dłużej (matowa = przebita). Kwas (kremortartar/cytryna) stabilizuje.", "zrodlo": "Złoty Standard Bezy v2026-06-13"}, {"id": "sc-054", "kategoria": "jakosc", "warunek": "Reklamacja 'mokry spód' tarty / planowanie tart z wilgotnym nadzieniem", "rada": "Chablonage: po blind bakingu posmaruj dno cienką warstwą temperowanej czekolady lub masła kakaowego — tania bariera przeciw wilgoci z nadzienia. Blind baking 160–175°C z obciążeniem 12–15 min + dosuszenie do złotego koloru.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. III)"}, {"id": "sc-055", "kategoria": "skalowanie", "warunek": "Wyliczanie masy ciasta na zamówioną liczbę sztuk (drożdżowe słodkie)", "rada": "Wydajność ciasta słodkiego 160–175% mąki, ubytek wypiekowy 7–10% — licz masę ciasta od masy wyrobu z zapasem na ubytek. Gramatury kęsów trzymaj stałe (bułka 60–80 g, rogal 60–70 g, drożdżówka 70–80 g + 40–50 g masy): równa gramatura = równy wypiek i stały foodcost.", "zrodlo": "Złoty Standard Ciast Wzbogaconych v2026-06-13; Instrukcja Ciasto Słodkie Drożdżowe v2026-06-13"}, {"id": "sc-056", "kategoria": "skalowanie", "warunek": "Receptura z cukrem powyżej ~15%", "rada": "Drożdże mają trudniej osmotycznie: daj więcej drożdży, wydłuż rozrost albo użyj drożdży osmotolerantnych (obowiązkowo rozważ przy >15–18% cukru). Zaparka tang zhong ~5% mąki = miększy i trwalszy miękisz (niższa aw).", "zrodlo": "Złoty Standard Ciast Wzbogaconych v2026-06-13"}, {"id": "sc-057", "kategoria": "skalowanie", "warunek": "Planowanie miksu asortymentu / redukcja straty", "rada": "Buduj kartę świadomie z części trwałej (niska aw: ganache, bonbony, kruche, ciastka maślane, karmel, beza sucha, curd) i części świeżej 'na wieczór' (kremy, musy, parzone nadziewane, entremets). Trwałe = bufor i niska strata; świeże = pozycjonowanie.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. IX); Złoty Standard Cukiernictwa v2026-06-13"}, {"id": "sc-058", "kategoria": "skalowanie", "warunek": "Decyzje o wielkości partii / zawężeniu karty 18 produktów", "rada": "Bez danych sprzedaży per produkt (analiza ABC) decyzja o partiach i wąskiej karcie to zgadywanie — standard wskazuje to jako blokujące wąskie gardło. Zbieraj wolumeny sprzedaży per produkt; do tego czasu wielkości partii = do kalibracji WSP.", "zrodlo": "Złoty Standard Cukiernictwa v2026-06-13; Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. IX)"}, {"id": "sc-059", "kategoria": "skalowanie", "warunek": "Skalowanie planu mrożenia insertów w górę", "rada": "Mrożenie insertów zakłada wydajne mrożenie: bez blast freezera mroź w cienkich warstwach i zaakceptuj gorszą teksturę delikatnych musów; przed skalowaniem sprawdź pojemność zamrażarki i chłodni (wielokrotnie wskazywane wąskie gardło). Decyzja o blaście — po policzeniu ROI.", "zrodlo": "Kompendium Cukiernictwa Rozszerzone v2026-06-17 (cz. VIII); Złoty Standard Cukiernictwa v2026-06-13"}, {"id": "sc-060", "kategoria": "kolejnosc", "warunek": "Pakowanie i wydanie entremets / tart / delikatnych deserów", "rada": "Pudło zawsze wyższe niż deser (wieko nie może dotknąć glazury — uszkodzenie nieodwracalne); tarty z nappage płasko, bez przechyłu; entremets przenoś na sztywnej podstawie; kruchy dekor czekoladowy transportuj osobno i montuj na miejscu.", "zrodlo": "Cukiernictwo Część XIII Pakowanie i Transport"}],
autorytety: [{"id": "aut-01", "nazwa": "Pierre Hermé", "rola": "Pâtissier, Paryż", "slynie_z": "\"Picasso patisserie\"; makaroniki i kolekcje smaków (Ispahan, Infiniment); haute couture w cukiernictwie", "praktyka": "Planowanie kolekcjami sezonowymi ogłaszanymi z wyprzedzeniem (jak dom mody). Jeden smak-matka (np. Ispahan: róża-liczi-malina) jest deklinowany na wiele form: makaronik, tarta, croissant, ciastko. Dzięki temu jedna decyzja smakowa zasila kilkanaście SKU, a produkcja korzysta z tych samych baz.", "zastosowanie": "Oliwia planuje 4 kolekcje rocznie i deklinuje 2-3 smaki przewodnie na istniejące formy (tarta, monoporcja, drożdżówka) zamiast wymyślać 18 osobnych produktów.", "kategoria": "patisserie"}, {"id": "aut-02", "nazwa": "Cédric Grolet", "rola": "Szef cukierni Le Meurice, Paryż", "slynie_z": "Owoce-trompe-l'oeil, kultowe kolejki, butiki z limitowaną dzienną produkcją", "praktyka": "Produkcja dzienna w ściśle limitowanych partiach — sprzedaż do wyczerpania zamiast produkcji \"na zapas\". Brygada pracuje w blokach: rano montaż i glazurowanie, dzień wcześniej wkłady i mrożenie. Krótka karta (kilkanaście pozycji), perfekcyjnie powtarzalna.", "zastosowanie": "Alterbake ustala dzienne limity na topowe SKU i komunikuje \"do wyczerpania\" — kontrolowany niedosyt zamiast strat; wkłady i inserty robione dzień wcześniej.", "kategoria": "patisserie"}, {"id": "aut-03", "nazwa": "Philippe Conticini", "rola": "Pâtissier, Paryż; współtwórca Pâtisserie des Rêves", "slynie_z": "Redefinicja klasyki francuskiej (Paris-Brest z wkładem pralinowym), architektura smaku warstwami", "praktyka": "Rozbijanie deseru na moduły (biszkopt, krem, wkład, chrupka, glazura) i standaryzowanie każdego modułu jako osobnej receptury bazowej z tolerancjami. Moduły są produkowane niezależnie, magazynowane i składane na koniec — planowanie dotyczy modułów, nie gotowych ciastek.", "zastosowanie": "Oliwia prowadzi plan produkcji na poziomie modułów (kremy, wkłady, spody), a nie gotowych SKU — jeden arkusz baz pokrywa całą witrynę.", "kategoria": "patisserie"}, {"id": "aut-04", "nazwa": "Christophe Michalak", "rola": "Pâtissier, Paryż; mistrz świata cukiernictwa 2005", "slynie_z": "Demokratyzacja patisserie, format \"fast good\" — desery wysokiej klasy przygotowywane szybko i prosto", "praktyka": "Świadome upraszczanie: eliminowanie kroków, które nie wnoszą smaku ani wyglądu, i projektowanie deserów pod realny czas pracy zespołu. Receptura ma być wykonalna przez przeciętnego cukiernika w przewidywalnym czasie, nie tylko przez mistrza.", "zastosowanie": "Każdy nowy produkt Alterbake przechodzi test: czy pomoc kuchenna wykona go po jednym przeszkoleniu? Jeśli nie — upraszczamy albo produkt zostaje sezonowym specjałem mistrza.", "kategoria": "patisserie"}, {"id": "aut-05", "nazwa": "Dominique Ansel", "rola": "Pâtissier-przedsiębiorca, Nowy Jork", "slynie_z": "Cronut (2013) — najgłośniejsza premiera produktu w historii cukiernictwa; kultura dropów i limitów", "praktyka": "Pipeline innowacji w rytmie kalendarza: nowy smak Cronuta co miesiąc, ogłaszany z wyprzedzeniem; dzienne limity produkcji utrzymujące jakość i popyt. Nowości testowane w małej skali w \"kuchni eksperymentalnej\" zanim wejdą do produkcji.", "zastosowanie": "Alterbake wprowadza \"produkt miesiąca\" z zapowiedzią w social mediach i dziennym limitem — jeden slot w planie produkcji zarezerwowany na rotującą nowość.", "kategoria": "patisserie"}, {"id": "aut-06", "nazwa": "Antonio Bachour", "rola": "Pâtissier, Miami; tło hotelowe (St. Regis, Fontainebleau)", "slynie_z": "Produkcja wolumenowa bez utraty finezji; mistrz form silikonowych i glazur lustrzanych; Best Pastry Chef 2018/2022", "praktyka": "Strategiczne mrożenie jako oś planowania: monoporcje i wkłady produkowane w dużych partiach do form silikonowych, mrożone, potem glazurowane i wykańczane w dniu sprzedaży. Rozdziela \"dni produkcji\" od \"dni wykańczania\", co wygładza obciążenie zespołu.", "zastosowanie": "Oliwia planuje 1-2 \"dni mroźnicze\" w tygodniu (duże partie wkładów i monoporcji do zamrażarki), a codziennie tylko wykańczanie — piec i ręce mistrza wolne na pieczywo świeże.", "kategoria": "patisserie"}, {"id": "aut-07", "nazwa": "Amaury Guichon", "rola": "Pâtissier-chocolatier, Las Vegas; Pastry Academy", "slynie_z": "Rzeźby czekoladowe i wiralowe wideo procesu; szkoła ucząca techniki krok po kroku", "praktyka": "Ekstremalna dokumentacja procesu: każdy etap rozpisany, sfilmowany i rozłożony na kroki możliwe do nauczenia. Skomplikowany projekt dzieli na fazy z punktami kontrolnymi, dzięki czemu wielodniowa praca jest planowalna i przejmowalna przez uczniów.", "zastosowanie": "Alterbake nagrywa telefonem krótkie wideo wzorcowego wykonania każdej bazy — biblioteka szkoleniowa skraca wdrożenie nowej pomocy z tygodni do dni.", "kategoria": "patisserie"}, {"id": "aut-08", "nazwa": "Johan Martin", "rola": "Pâtissier-konsultant i szkoleniowiec (Bellouet Conseil), Paryż", "slynie_z": "Wiennoiserie na poziomie mistrzowskim — laminowane croissanty, brioszki, konsulting dla cukierni na całym świecie", "praktyka": "Planowanie wsteczne wielodniowych procesów laminacji: od godziny wypieku liczy się do tyłu przez garowanie, formowanie, składania i odpoczynek ciasta w chłodni. Harmonogram laminacji jest szkieletem tygodnia — reszta produkcji dokleja się do niego.", "zastosowanie": "Croissanty i drożdżówki Alterbake mają stały 2-dniowy harmonogram wsteczny (D-1: ciasto i laminacja, D: formowanie-garowanie-wypiek), wpisany na stałe w plan tygodnia.", "kategoria": "patisserie"}, {"id": "aut-09", "nazwa": "Yann Couvreur", "rola": "Pâtissier, Paryż (sieć butików bez zaplecza pałacowego)", "slynie_z": "Patisserie \"instantanée\" — desery bez konserwantów, składane na oczach klienta, krótkie serie", "praktyka": "Świeżość jako parametr planistyczny: produkty projektowane pod maksymalnie krótki czas życia w witrynie, produkcja w kilku małych rzutach dziennie zamiast jednego dużego rano. Mniej strat, witryna zawsze wygląda na żywą.", "zastosowanie": "Zamiast jednej porannej produkcji, Alterbake robi drugi mini-rzut ok. 11:00 (dopiek drożdżówek, dokładanie monoporcji) — witryna pełna po południu bez porannej nadprodukcji.", "kategoria": "patisserie"}, {"id": "aut-10", "nazwa": "Jordi Roca", "rola": "Szef deserów El Celler de Can Roca, Girona; najlepszy cukiernik świata 2014", "slynie_z": "Awangardowe desery (zapachy, perfumy jadalne); Rocambolesc — przełożenie fine diningu na format uliczny", "praktyka": "Zorganizowana kreatywność: osobny czas i przestrzeń na eksperymenty (warsztat kreatywny La Masia), oddzielone od bieżącej produkcji. Pomysł przechodzi formalną ścieżkę: koncept → prototyp → degustacja zespołu → dopiero potem karta.", "zastosowanie": "W Alterbake eksperymenty mają swój slot (np. wtorek 13-15) i nie wolno ich robić \"przy okazji\" w środku produkcji — chroni to i produkcję, i kreatywność.", "kategoria": "patisserie"}, {"id": "aut-11", "nazwa": "William Curley", "rola": "Chocolatier-pâtissier, Londyn; wielokrotnie najlepszy chocolatier Wielkiej Brytanii", "slynie_z": "Mała manufaktura czekolady i patisserie najwyższej jakości prowadzona kilkuosobowym zespołem", "praktyka": "Model małego zespołu premium: wąski asortyment robiony perfekcyjnie, produkcja pralin w partiach tygodniowych (dojrzewanie ganache to element planu), cross-training całego zespołu, żeby nieobecność jednej osoby nie zatrzymała produkcji.", "zastosowanie": "Oliwia utrzymuje macierz kompetencji: każda z 18 pozycji ma co najmniej 2 osoby umiejące ją wykonać; urlop czy L4 nie wywraca tygodnia.", "kategoria": "patisserie"}, {"id": "aut-12", "nazwa": "Claire Saffitz", "rola": "Autorka i edukatorka (ex-Bon Appétit), Nowy Jork", "slynie_z": "\"Dessert Person\"; metodyczne testowanie receptur i tłumaczenie, dlaczego coś działa", "praktyka": "Testowanie iteracyjne z notacją zmian: każda próba receptury ma zapisane, co zmieniono i jaki był efekt; receptura jest \"gotowa\" dopiero po powtórzeniu wyniku. Publikowana receptura zawiera znaki sensoryczne (jak ma wyglądać, pachnieć, sprężynować) zamiast samych liczb.", "zastosowanie": "Karta testu nowego produktu w Alterbake: data, zmiana, wynik, zdjęcie; produkt wchodzi do witryny po 2 powtarzalnych próbach, nie po jednej udanej.", "kategoria": "jakosc"}, {"id": "aut-13", "nazwa": "Chad Robertson", "rola": "Piekarz, Tartine Bakery, San Francisco", "slynie_z": "\"Tartine Bread\"; chleb sprzedawany prosto z pieca po południu; kult świeżości i fermentacji", "praktyka": "Odwrócenie doby piekarskiej pod moment sprzedaży: wypiek zaplanowany tak, by chleb trafiał do klienta w szczycie swojej jakości, a nie w szczycie wygody produkcji. Cała fermentacja liczona wstecz od godziny sprzedaży; produkcja dokładnie w ilości, która się sprzeda.", "zastosowanie": "Alterbake planuje wypieki pod godziny szczytu sprzedaży (poranny 7-9 i popołudniowy 15-17), zamiast piec wszystko przed otwarciem.", "kategoria": "piekarstwo"}, {"id": "aut-14", "nazwa": "Apollonia Poilâne", "rola": "CEO Poilâne, Paryż (3. pokolenie)", "slynie_z": "Skalowanie rzemiosła bez industrializacji: \"retro-innowacja\", manufaktura, w której każdy piekarz odpowiada za bochenek od początku do końca", "praktyka": "Skalowanie przez replikację jednostki rzemieślniczej zamiast taśmy: więcej kompletnych stanowisk mistrzowskich, nie podział pracy na mikroczynności. Jakość audytowana codziennie przez właściciela (Apollonia degustuje chleb każdego dnia).", "zastosowanie": "Gdy Alterbake urośnie, dokłada drugi kompletny zespół zmianowy (mistrz + pomoc), a nie tnie pracy na taśmę; codzienna degustacja witryny przez Oliwię jako rytuał jakości.", "kategoria": "piekarstwo"}, {"id": "aut-15", "nazwa": "Jeffrey Hamelman", "rola": "Piekarz-edukator, King Arthur Baking; autor \"Bread\"", "slynie_z": "Biblia zawodowego piekarstwa z harmonogramami produkcji i matematyką piekarską (baker's percentage)", "praktyka": "Formalne harmonogramy dnia piekarni: rozpisanie każdego procesu na osi czasu z nakładaniem się etapów (gdy jedno ciasto fermentuje, drugie się formuje). Procenty piekarskie umożliwiają natychmiastowe przeliczanie partii w górę i w dół bez błędów.", "zastosowanie": "Wszystkie receptury Alterbake przepisane na procenty względem mąki/bazy — Oliwia skaluje partię jednym mnożnikiem; dzień rozpisany na osi czasu z nakładkami procesów.", "kategoria": "piekarstwo"}, {"id": "aut-16", "nazwa": "Nancy Silverton", "rola": "Piekarka-restauratorka, La Brea Bakery / Mozza, Los Angeles", "slynie_z": "Skalowanie piekarni zakwasowej od butiku do dużej marki bez utraty charakteru; \"Breads from the La Brea Bakery\"", "praktyka": "Standaryzacja żywych procesów: zakwas i fermentacja prowadzone według mierzalnych parametrów (temperatura, czas, wygląd, zapach), by dały się przekazać zespołowi i skalować. Rozdzielenie tego, co skalowalne (bazy, procesy), od tego, co butikowe (wykończenie).", "zastosowanie": "Karty prowadzenia zakwasu i kremów z parametrami liczbowymi + znakami sensorycznymi wiszą przy stanowiskach — każda zmiana prowadzi je tak samo.", "kategoria": "piekarstwo"}, {"id": "aut-17", "nazwa": "Richard Bertinet", "rola": "Piekarz-edukator, Bath (Wielka Brytania); The Bertinet Kitchen", "slynie_z": "Szkoła piekarska, technika \"slap and fold\"; przekładanie rzemiosła na proste, nauczalne ruchy", "praktyka": "Delegacja przez technikę, nie przez talent: rozbicie rzemiosła na kilka powtarzalnych ruchów i uczenie ich do automatyzmu. Nowa osoba dostaje jedną technikę do opanowania naraz, z jasnym kryterium \"umie / jeszcze nie umie\".", "zastosowanie": "Onboarding pomocy w Alterbake: tydzień 1 — ważenie i wałkowanie, tydzień 2 — szprycowanie, tydzień 3 — wykańczanie; każdy etap z egzaminem praktycznym u Oliwii.", "kategoria": "piekarstwo"}, {"id": "aut-18", "nazwa": "Bo Friberg", "rola": "Autor-edukator, \"The Professional Pastry Chef\" (California Culinary Academy)", "slynie_z": "Najbardziej kompletny podręcznik zawodowego cukiernictwa; systematyka mise en place i planów pracy", "praktyka": "Plan pracy jako dokument pisany przed rozpoczęciem produkcji: lista zadań w kolejności wykonania, z zaznaczeniem, co można robić równolegle i co czeka (chłodzenie, pieczenie). Mise en place rozumiane szeroko — przygotowanie sprzętu, form i głowy, nie tylko składników.", "zastosowanie": "Wieczorem Oliwia (lub zmiana) wypisuje jutrzejszy plan dnia na tablicy: kolejność, kto, co równolegle — rano nikt nie zaczyna od zastanawiania się.", "kategoria": "patisserie"}, {"id": "aut-19", "nazwa": "Peter Greweling", "rola": "Profesor CIA (Culinary Institute of America); autor \"Chocolates and Confections\"", "slynie_z": "Naukowe podstawy cukiernictwa: aktywność wody, shelf life, krystalizacja — liczby zamiast intuicji", "praktyka": "Dobór wielkości partii do trwałości produktu: partia ma sens tylko taka, jaką sprzedasz w oknie pełnej jakości (mierzonym aktywnością wody i warunkami przechowywania). Trwałość jest projektowana w recepturze, nie odkrywana po fakcie.", "zastosowanie": "Każde SKU Alterbake ma przypisane okno jakości (np. beza 3 dni, krem dzień, praliny 3 tygodnie) i maksymalną partię wynikającą z rotacji — koniec z \"zrobimy więcej, bo się miesza raz\".", "kategoria": "jakosc"}, {"id": "aut-20", "nazwa": "École Ferrandi", "rola": "Szkoła gastronomiczna, Paryż; podręcznik \"Pâtisserie\"", "slynie_z": "\"Harvard gastronomii\" — kanoniczny program kształcenia cukierników i organizacja pracowni", "praktyka": "Organizacja pracowni według stref procesów (strefa ciast, strefa kremów, strefa wykańczania, strefa mycia) i standard \"czystego przekazania\" stanowiska między osobami. Receptury dydaktyczne rozpisane z czasami i punktami krytycznymi, by były wykonywalne przez ucznia.", "zastosowanie": "Alterbake wyznacza stałe strefy stanowisk i zasadę: stanowisko oddajesz czyste i zatowarowane — kolejna osoba zaczyna natychmiast, bez szukania i mycia.", "kategoria": "patisserie"}, {"id": "aut-21", "nazwa": "Frédéric Bau / École Valrhona", "rola": "Pâtissier-twórca École Valrhona, Tain-l'Hermitage", "slynie_z": "Wynalazca czekolady Dulcey; \"Gourmandise Raisonnée\" — redukcja cukru i tłuszczu bez utraty przyjemności", "praktyka": "Receptury jako systemy proporcji, nie listy składników: Valrhona uczy tabel wymienności (jak zmiana czekolady o innej zawartości kakao przelicza się na resztę receptury). Innowacja prowadzona metodycznie — \"racjonalna przyjemność\" to program badawczy, nie hasło.", "zastosowanie": "Alterbake trzyma tabelę wymienności surowców (czekolady, śmietanki, przeciery) — zmiana dostawcy czy braki nie zatrzymują produkcji, tylko uruchamiają przelicznik.", "kategoria": "jakosc"}, {"id": "aut-22", "nazwa": "Eliyahu Goldratt", "rola": "Fizyk i teoretyk zarządzania; autor \"Celu\" (Teoria Ograniczeń)", "slynie_z": "Teoria ograniczeń (TOC): przepustowość systemu wyznacza wąskie gardło; werbel-bufor-lina", "praktyka": "Pięć kroków TOC: zidentyfikuj ograniczenie, wyciśnij z niego maksimum, podporządkuj mu resztę, dopiero potem inwestuj, i wracaj do kroku 1. Godzina stracona na wąskim gardle to godzina stracona dla całej firmy — planuje się od gardła, nie od początku procesu.", "zastosowanie": "W Alterbake wąskim gardłem jest piec: plan dnia buduje się od harmonogramu pieca (nigdy pusty, nigdy czekający na wsad), a mikser i stoły podporządkowują się jego rytmowi.", "kategoria": "strategia"}, {"id": "aut-23", "nazwa": "Taiichi Ohno", "rola": "Inżynier Toyoty; twórca Toyota Production System", "slynie_z": "Lean: eliminacja 7 marnotrawstw (muda), przepływ jednej sztuki, kanban, produkcja ssana (pull)", "praktyka": "Produkcja ciągniona przez popyt zamiast pchana przez plan: uzupełniaj to, co faktycznie ubyło, w małych partiach, i skracaj przezbrojenia, żeby małe partie były opłacalne. Marnotrawstwo to też czekanie ludzi, zbędny ruch po pracowni i nadprodukcja — najgorsza ze wszystkich.", "zastosowanie": "Witryna Alterbake działa jak kanban: poziomy minimalne na półkach wyzwalają dopieki; układ pracowni ustawiony tak, by mistrz nie robił kilometrów między piecem a stołem.", "kategoria": "strategia"}, {"id": "aut-24", "nazwa": "W. Edwards Deming", "rola": "Statystyk i teoretyk jakości; ojciec japońskiej rewolucji jakości", "slynie_z": "Cykl PDCA (Plan-Do-Check-Act), 14 zasad zarządzania, myślenie systemowe o jakości", "praktyka": "Większość błędów to wina systemu, nie ludzi: zamiast obwiniać pracownika za zakalec, poprawia się proces (recepturę, oznaczenia, kolejność). Decyzje na podstawie danych zbieranych stale, nie wrażeń; poprawa w małych cyklach PDCA zamiast wielkich rewolucji.", "zastosowanie": "Cotygodniowy 15-minutowy przegląd liczb (straty, sell-through, reklamacje) i jedna poprawka procesu na tydzień — Alterbake poprawia system, nie szuka winnych.", "kategoria": "jakosc"}, {"id": "aut-25", "nazwa": "David Chang", "rola": "Kucharz-przedsiębiorca, Momofuku, Nowy Jork", "slynie_z": "Skalowanie od jednego baru ramen do grupy restauracyjnej; kultura mise en place i brutalnej szczerości operacyjnej", "praktyka": "Mise en place jako filozofia zarządzania czasem i delegacją: przygotowanie jest pracą, a serwis tylko składaniem przygotowanego. Systemy i checklisty pozwalają młodym kucharzom prowadzić stacje od pierwszego dnia; szef projektuje system, nie gotuje wszystkiego sam.", "zastosowanie": "Alterbake oddziela \"produkcję baz\" (przedpołudnie, checklisty) od \"składania i wykańczania\" (krótkie okna, precyzja) — pomoc prowadzi bazy samodzielnie według list od 1. dnia.", "kategoria": "strategia"}],
sezon: [{"miesiac": 1, "nazwa": "Styczeń", "surowce": ["cytrusy (pomarańcza, cytryna, grejpfrut, kumkwat)", "mrożone owoce z lata (malina, porzeczka, wiśnia)", "orzechy z jesiennych zapasów", "mak, miód (końcówki świąteczne)"], "okazje": ["Nowy Rok / postanowienia (lżejsze, mniej słodkie)", "Dzień Babci i Dziadka (21-22.01)", "ferie zimowe (woj. śląskie zwykle w styczniu/lutym)", "karnawał — pierwsze zamówienia na bale"], "produkty": ["tarty i monoporcje cytrusowe", "serniki lżejsze (cytryna, limonka)", "drobne ciastka do kawy dla seniorów (Dzień Babci/Dziadka — zestawy prezentowe)", "pierwsze partie testowe pączków przed Tłustym Czwartkiem"], "planowanie": "Miesiąc niskiej sprzedaży detalicznej — idealny na inwentaryzację receptur, szkolenie pomocy i testy pączków. Zaplanuj już teraz logistykę Tłustego Czwartku (zamówienia surowców: smalec/olej, marmolada róża, drożdże; grafik nocnej zmiany). Zbuduj zapas mrożonych wkładów na luty."}, {"miesiac": 2, "nazwa": "Luty", "surowce": ["róża (konfitura), marmolada wieloowocowa", "cytrusy nadal w szczycie", "mrożona malina i wiśnia", "smalec/olej do smażenia w hurtowych ilościach"], "okazje": ["TŁUSTY CZWARTEK (ruchomy: luty lub początek marca) — największy dzień roku dla pączków", "Walentynki (14.02)", "ostatki/śledzik", "ferie zimowe"], "produkty": ["pączki (róża, adwokat, słony karmel; wersja premium i klasyczna), faworki, oponki", "monoporcje walentynkowe (serca: malina-czekolada, pistacja-róża)", "mini-desery dla par, boxy walentynkowe"], "planowanie": "Tłusty Czwartek planuj jak operację wojskową: przedsprzedaż z odbiorem na godzinę (wygładza kolejkę i daje pewny wolumen), nocna zmiana smażenia, uproszczona karta pozostałych SKU tego dnia do absolutnego minimum. Walentynki to głównie piątek/weekend przed 14.02 — nie przeceniaj wolumenu w dzień powszedni."}, {"miesiac": 3, "nazwa": "Marzec", "surowce": ["rabarbar szklarniowy (koniec marca)", "cytrusy schodzą", "mak, ser twarogowy, bakalie (przygotowania wielkanocne)", "pierwsza zieleń dekoracyjna"], "okazje": ["Dzień Kobiet (8.03)", "początek wiosny — zmiana witryny na jaśniejszą", "Wielki Post (część klientów ogranicza słodycze)", "jeśli Wielkanoc wypada w marcu — pełny tryb świąteczny"], "produkty": ["babeczki i monoporcje na Dzień Kobiet (tulipany, pastele)", "pierwsze tarty rabarbarowe", "testy i przedsprzedaż wielkanocna: mazurki, baby drożdżowe i piaskowe, serniki"], "planowanie": "Post realnie obniża sprzedaż w tygodniu — zmniejsz partie codzienne o 10-15% i przerzuć moce na przygotowania wielkanocne: mrożenie spodów do mazurków, testy dekoracji, sesja zdjęciowa oferty świątecznej i uruchomienie zamówień przedświątecznych do końca miesiąca."}, {"miesiac": 4, "nazwa": "Kwiecień", "surowce": ["rabarbar (pełnia sezonu krajowego pod koniec miesiąca)", "twaróg, jaja, mak, bakalie, lukier, biała czekolada", "pierwsze polskie szparagi jako ciekawostka (dekoracje wytrawne)"], "okazje": ["WIELKANOC (najczęściej kwiecień) — drugi szczyt roku", "Lany Poniedziałek", "po świętach: tydzień zdecydowanego dołka sprzedaży"], "produkty": ["mazurki (królewski, kajmakowy, cytrynowy, czekoladowy)", "baby wielkanocne drożdżowe i piaskowe z lukrem", "serniki wiedeńskie, paschy", "figurki i pisanki z czekolady", "po świętach: lekkie tarty rabarbarowe"], "planowanie": "Wielkanoc = 90% wolumenu na zamówienia z odbiorem w Wielki Piątek/Sobotę. Zamknij przyjmowanie zamówień z 5-dniowym wyprzedzeniem, rozpisz produkcję wstecz (mazurki -3 dni na spodach z mrożnika, baby -1 dzień). Tydzień po świętach tnij produkcję o 30% — klienci mają domowe ciasta."}, {"miesiac": 5, "nazwa": "Maj", "surowce": ["rabarbar w pełni", "pierwsze polskie truskawki (koniec maja, szklarniowe wcześniej)", "kwiaty jadalne, zioła (werbena, mięta)", "śmietanka — sezon tortowy startuje"], "okazje": ["KOMUNIE (soboty i niedziele maja) — sezon tortów i pakietów", "majówka (1-3.05)", "Dzień Matki (26.05)"], "produkty": ["torty komunijne i paczki ciast na przyjęcia (blaszki, mini-desery, słodkie stoły)", "bezy i torty bezowe z truskawką i rabarbarem", "monoporcje truskawkowe", "eleganckie boxy na Dzień Matki"], "planowanie": "Komunie rezerwują weekendowe moce na 2-3 tygodnie naprzód — prowadź kalendarz zamówień z limitem tortów na sobotę (np. maks. 6) i nie przyjmuj ponad limit. Przerzuć produkcję witrynową na piątek. Majówka: mniejsze partie w dni wyjazdowe, więcej formatu piknikowego (ciastka, drożdżówki)."}, {"miesiac": 6, "nazwa": "Czerwiec", "surowce": ["truskawka (szczyt sezonu polskiego)", "czereśnia", "pierwsze maliny i porzeczki (koniec miesiąca)", "rabarbar kończy sezon"], "okazje": ["Dzień Dziecka (1.06)", "Boże Ciało (ruchome) — długi weekend", "komunie (pierwsza połowa)", "zakończenie roku szkolnego (torty, podziękowania dla nauczycieli)", "początek sezonu ślubnego"], "produkty": ["wszystko z truskawką: tarty, torty bezowe, monoporcje, drożdżówki z owocem", "kolorowe babeczki na Dzień Dziecka", "torty na zakończenie roku i pierwsze wesela", "lody/sorbety własne jeśli w ofercie"], "planowanie": "Truskawka nie czeka: kupuj codziennie małe partie od sprawdzonego dostawcy, nadwyżki natychmiast przerabiaj na kulisy i konfitury do mrożenia (tani surowiec teraz = wkłady na cały rok). Upały zaczynają zabijać kremy maślane — przestaw witrynę na musy, bezy i owoce."}, {"miesiac": 7, "nazwa": "Lipiec", "surowce": ["malina, jagoda, borówka, porzeczki, wiśnia", "morele i pierwsze brzoskwinie", "ostatnie truskawki"], "okazje": ["wakacje — odpływ stałych klientów, napływ okazjonalnych", "sezon ślubny w pełni (soboty)", "upały — zmiana zachowań zakupowych"], "produkty": ["jagodzianki (kultowy produkt lata — potrafią być hitem wolumenowym)", "tarty i monoporcje z maliną i borówką", "lżejsze desery: musy, panna cotta, sorbety", "torty weselne wg kalendarza zamówień"], "planowanie": "Zaplanuj urlopy zespołu TERAZ na zasadzie: nigdy mistrz i doświadczona pomoc jednocześnie. Zredukuj kartę do sprawdzonych 12-14 SKU na czas urlopów. Jagodzianki traktuj jak produkt flagowy lata — stały słot pieca każdego ranka. Mroź maliny i porzeczki na zimowe wkłady."}, {"miesiac": 8, "nazwa": "Sierpień", "surowce": ["śliwka węgierka (od połowy miesiąca!)", "brzoskwinia, morela", "jeżyna, późne maliny", "pierwsze jabłka letnie"], "okazje": ["sezon ślubny trwa", "15.08 — długi weekend", "końcówka wakacji, powroty klientów pod koniec miesiąca", "dożynki lokalne"], "produkty": ["drożdżówki i ciasta ze śliwką (kruszonka!)", "tarty z brzoskwinią i jeżyną", "torty weselne", "od końca sierpnia: powrót pełnej karty"], "planowanie": "Węgierka to najlepszy stosunek jakości do ceny w roku — wjazd na witrynę szeroko i mrożenie połówek na zimę. Pod koniec miesiąca stopniowo zwiększaj partie (powroty z wakacji) i zaplanuj wrześniową kolekcję jesienną, żeby 1 września nie zaskoczył."}, {"miesiac": 9, "nazwa": "Wrzesień", "surowce": ["śliwka w pełni, jabłka i gruszki nowego zbioru", "orzechy laskowe i włoskie świeże", "figa importowana w dobrej cenie", "pierwsza dynia"], "okazje": ["powrót do szkoły/pracy — odbudowa rutyny zakupowej", "sezon urodzinowo-imprezowy wraca", "ostatnie wesela"], "produkty": ["szarlotki i tarty jabłkowe (klasyk jesieni)", "ciasta ze śliwką, powidła własne", "monoporcje gruszka-orzech, śliwka-cynamon", "powrót cięższych deserów: karmel, orzech, czekolada"], "planowanie": "Wrzesień to reset roczny: przegląd wyników lata (sell-through per SKU), wycinka najsłabszych 2-3 pozycji, wprowadzenie kolekcji jesiennej. Zrób dzień produkcji powideł i konfitur śliwkowych na cały sezon. Zacznij planować personel i surowce na Q4 (najcięższy kwartał)."}, {"miesiac": 10, "nazwa": "Październik", "surowce": ["dynia (szczyt)", "jabłko, gruszka, pigwa", "orzechy, kasztany jadalne", "czekolada — start sezonu ciężkich smaków"], "okazje": ["Halloween (31.10) — rosnące, zwłaszcza dla młodszych klientów", "jesienna aura sprzyja deserom i kawie — dobry ruch popołudniowy", "przygotowania do Wszystkich Świętych"], "produkty": ["tarty i serniki dyniowe (pumpkin spice działa też w Polsce)", "desery kasztanowe i orzechowe", "monoporcje Halloween (limitowana seria, 1-2 SKU max)", "pierwsze pierniki — ciasto piernikowe dojrzewające musi powstać TERAZ"], "planowanie": "Zagniataj ciasto na pierniki dojrzewające w październiku (4-6 tygodni leżakowania do Bożego Narodzenia). Halloween traktuj jako mały test kreatywny, nie duży wolumen. Zaplanuj i sfotografuj ofertę bożonarodzeniową do końca miesiąca — firmy pytają o zamówienia świąteczne już w listopadzie."}, {"miesiac": 11, "nazwa": "Listopad", "surowce": ["mak, miód, bakalie, przyprawy korzenne (zakupy hurtowe na święta)", "jabłka, gruszki, cytrusy wracają", "kasztan, orzech"], "okazje": ["Wszystkich Świętych (1.11) — ruch przy cmentarzach, ciasta \"na stół rodzinny\"", "11 listopada — rogale świętomarcińskie (tradycja wykracza poza Poznań)", "Andrzejki (29/30.11)", "start zamówień firmowych na święta", "Black Friday — ew. promocja na przedsprzedaż świąteczną"], "produkty": ["rogale z białym makiem (św. Marcin) — produkt eventowy z przedsprzedażą", "ciasta rodzinne: seromakowce, jabłeczniki", "pierniki wczesne, kalendarze adwentowe z pralinami (przedsprzedaż!)", "słodkie stoły na Andrzejki"], "planowanie": "Listopad to miesiąc przedsprzedaży: otwórz zamówienia świąteczne (osoby prywatne + firmy) z cennikiem i deadline'em ok. 10-14.12. Kalendarze adwentowe muszą być gotowe do sprzedaży do 25.11. Rogale świętomarcińskie planuj jak mini-Tłusty Czwartek: przedsprzedaż + dedykowany blok pieca 10-11.11."}, {"miesiac": 12, "nazwa": "Grudzień", "surowce": ["mak, miód, bakalie, kasztany, cytrusy (pomarańcza+goździki)", "czekolada w maksymalnym zużyciu rocznym", "wanilia, przyprawy korzenne"], "okazje": ["Mikołajki (6.12)", "BOŻE NARODZENIE — największy tydzień roku (zamówienia z odbiorem 22-24.12)", "zamówienia firmowe (pierwsze 2 tygodnie)", "Sylwester (31.12)"], "produkty": ["makowce, serniki świąteczne, pierniki dojrzewające i pierniczki dekorowane", "keksy, strucle, mini-desery na firmowe prezenty", "praliny i figurki mikołajowe z czekolady", "na Sylwestra: monoporcje imprezowe, mini-desery, torty sylwestrowe"], "planowanie": "Podziel grudzień na 3 fale: (1) 1-14.12 firmy i Mikołajki, (2) 15-24.12 święta detaliczne — zamknij zamówienia ok. 18.12, produkcja wsteczna od odbiorów 23-24.12, mrożone spody i wkłady przygotowane w listopadzie ratują przepustowość, (3) 27-31.12 Sylwester na małej, imprezowej karcie. Między 24 a 27.12 daj zespołowi realny oddech — styczeń wybaczy."}],
trendy: [{"id": "tr-01", "nazwa": "Pistacja + \"Dubai chocolate\" (kadaif)", "opis": "Globalny wiral tabliczki z kremem pistacjowym i chrupiącym kadaifem przeniósł się na croissanty, pączki i monoporcje; pistacja stała się smakiem numer 1 cukiernictwa.", "sila": 5, "horyzont": "teraz", "dopasowanie_alterbake": "Nie kopiować tabliczki (rynek nasycony), tylko przenieść duet pistacja-kadaif na własne formy: pączek na Tłusty Czwartek, monoporcja, drożdżówka. Jeden krem pistacjowy jako baza zasila 3 SKU bez nowego slotu pieca.", "przyklad": "Fix Dessert Chocolatier (Dubaj) — oryginał; w Polsce fala od cukierni rzemieślniczych po sieciówki"}, {"id": "tr-02", "nazwa": "Hybrydy viennoiserie (crookie, croissant-formaty)", "opis": "Krzyżówki na bazie ciasta croissantowego: crookie (croissant + ciastko cookie), płaskie croissanty, croissanty nadziewane premium. Jedno ciasto-matka, wiele wiralowych form.", "sila": 4, "horyzont": "teraz", "dopasowanie_alterbake": "Idealne przy 2 piecach: laminowane ciasto już jest w produkcji, hybryda to tylko inne formowanie i nadzienie. Rotacyjny \"croissant miesiąca\" jako produkt-magnes bez zwiększania liczby baz.", "przyklad": "Boulangerie Louvard (Paryż) — crookie; Cédric Grolet — croissanty premium"}, {"id": "tr-03", "nazwa": "Mniej cukru, czystszy smak", "opis": "Świadoma redukcja słodyczy w deserach premium — kwasowość owoców, gorycz kakao i sól jako kontrapunkty. Klient premium czyta \"mniej słodkie\" jako \"bardziej rzemieślnicze\".", "sila": 4, "horyzont": "teraz", "dopasowanie_alterbake": "Przegląd 18 SKU pod kątem redukcji cukru o 10-20% tam, gdzie nie psuje struktury; komunikacja \"mniej słodkie niż myślisz\" przy witrynie. Zero kosztu, realna dyferencjacja.", "przyklad": "Frédéric Bau / Valrhona — program \"Gourmandise Raisonnée\" (Francja)"}, {"id": "tr-04", "nazwa": "Hiperlokalne i sezonowe owoce", "opis": "Krótkie serie deserów z owocem od konkretnego lokalnego dostawcy, z nazwiskiem sadownika na wywieszce. Sezonowość jako marketing, nie ograniczenie.", "sila": 4, "horyzont": "teraz", "dopasowanie_alterbake": "Śląsk/okolice: truskawka z konkretnego gospodarstwa, śliwka węgierka, rabarbar. Jedna \"tarta sezonowa\" jako stały slot w karcie ze zmiennym owocem — witryna żyje bez zmiany procesu produkcji.", "przyklad": "Yann Couvreur (Paryż), Lune Croissanterie (Melbourne) — sezonowe rotacje"}, {"id": "tr-05", "nazwa": "Torty vintage / płaskie torty dekorowane", "opis": "Powrót retro-estetyki: lambeth piping, pastelowe kolory, kokardki, minimalistyczne płaskie torty z napisem. Silny popyt na urodziny, wieczory panieńskie, małe wesela.", "sila": 4, "horyzont": "teraz", "dopasowanie_alterbake": "Segment zamówieniowy o wysokiej marży niewymagający pieca w dniu zamówienia (biszkopty z mrożnika). Limit 4-6 tortów na weekend, cennik od wzoru, portfolio na Instagramie.", "przyklad": "trend globalny z Instagrama/TikToka; w Polsce pracownie butikowe w każdym większym mieście"}, {"id": "tr-06", "nazwa": "Tekstura crunch jako obowiązek", "opis": "Każdy deser musi mieć wyraźny element chrupiący: praliné feuilletine, kadaif, kruszonki, karmelizowane orzechy, sablé. Tekstura wyprzedziła dekorację jako kryterium jakości.", "sila": 4, "horyzont": "teraz", "dopasowanie_alterbake": "Audyt 18 SKU: każdy ma mieć świadomy element chrupiący. Wystarczą 2-3 uniwersalne \"crunche\" robione raz w tygodniu w dużej partii (trzymają się doskonale w szczelnym pojemniku).", "przyklad": "Antonio Bachour, Johan Martin — warstwa chrupiąca jako standard kompozycji"}, {"id": "tr-07", "nazwa": "Przejrzystość składu i \"czysta etykieta\"", "opis": "Klient pyta o skład: masło czy margaryna, prawdziwa wanilia, bez ulepszaczy. Cukiernie rzemieślnicze wygrywają otwartą komunikacją pełnego składu.", "sila": 4, "horyzont": "teraz", "dopasowanie_alterbake": "Wywieszki przy witrynie: \"100% masła, bez mieszanek i ulepszaczy\" + pełny skład każdego SKU dostępny na kartach. Uzasadnia cenę premium względem sieciówek — koszt zerowy.", "przyklad": "Poilâne (Paryż), polskie piekarnie rzemieślnicze nowej fali (np. nurt zakwasowy)"}, {"id": "tr-08", "nazwa": "Desery roślinne (wege) jako pozycja stała", "opis": "Nie osobna \"wege-karta\", lecz 1-2 pełnowartościowe desery roślinne w standardowej ofercie, na tyle dobre, że kupują je wszyscy. Techniki: aquafaba, tłuszcze roślinne, musy owocowe.", "sila": 3, "horyzont": "6mies", "dopasowanie_alterbake": "Jedno SKU roślinne zrobione porządnie (np. tarta czekoladowa na kremie z gorzkiej czekolady i mleka owsianego) zamiast pięciu przeciętnych. Otwiera zamówienia na eventy, gdzie 'opcja wege' jest warunkiem.", "przyklad": "Land&Monkeys (Paryż) — w pełni roślinna boulangerie-patisserie"}, {"id": "tr-09", "nazwa": "Fermentacja w deserach", "opis": "Zakwas w cieście na gofry/ciasta, miso w karmelu, koji, fermentowane owoce — głębia umami i kwasowości w słodkim. Trend z fine diningu schodzący do rzemiosła.", "sila": 2, "horyzont": "12mies", "dopasowanie_alterbake": "Niski koszt wejścia, bo zakwas już jest w piekarni: babka na zakwasie, karmel z nutą miso jako składnik jednej monoporcji. Traktować jako eksperyment w pipeline, nie filar oferty.", "przyklad": "Noma/René Redzepi (fermentacja), Tartine (San Francisco) — desery na zakwasie"}, {"id": "tr-10", "nazwa": "Single-origin kakao i pochodzenie surowca", "opis": "Czekolada z jednej plantacji/kraju z komunikacją pochodzenia (jak kawa speciality). Rosnąca świadomość cen kakao dodatkowo kieruje uwagę na jakość zamiast ilości.", "sila": 3, "horyzont": "6mies", "dopasowanie_alterbake": "Przy rekordowych cenach kakao: mniej czekolady, ale lepszej i z historią. Jedno SKU \"czekoladowe z metryczką\" (kraj, plantacja, procent) w wyższej cenie zamiast walki o marżę na masowej kuwerturze.", "przyklad": "William Curley (Londyn), polskie manufaktury bean-to-bar (np. nurt krakowski)"}, {"id": "tr-11", "nazwa": "Mini-formaty i degustacyjne boxy", "opis": "Zestawy 4-9 miniatur zamiast jednego dużego deseru: klient chce spróbować wszystkiego, box jest prezentowy i instagramowy, a cena za kg najwyższa w witrynie.", "sila": 4, "horyzont": "teraz", "dopasowanie_alterbake": "Box degustacyjny z miniatur istniejących 18 SKU — zero nowych receptur, tylko mniejsze formy. Idealny na prezenty, do biur i na okazje (Dzień Matki, Walentynki); świetnie zagospodarowuje końcówki partii.", "przyklad": "Bachour (Miami) — petit gâteaux boxy; polskie cukiernie butikowe"}, {"id": "tr-12", "nazwa": "Kolaboracje i produkty limitowane", "opis": "Cukiernia x palarnia kawy, x browar rzemieślniczy, x lokalny artysta — limitowany produkt tworzy szum, wymienia audiencje i nie obciąża stałej karty.", "sila": 3, "horyzont": "6mies", "dopasowanie_alterbake": "Kwartalna kolaboracja z gliwicką palarnią kawy lub lodziarnią: jeden wspólny produkt na 2 tygodnie, wzajemna promocja. Mieści się w slocie \"produkt miesiąca\" — bez zmian w harmonogramie pieca.", "przyklad": "Dominique Ansel (Nowy Jork) — seryjne kolaboracje; Lune x marki (Australia)"}, {"id": "tr-13", "nazwa": "Dropy i przedsprzedaż online", "opis": "Sprzedaż limitowanych partii przez zapisy/przedsprzedaż z odbiorem osobistym: pewny wolumen, zero strat, efekt ekskluzywności. Model przechodzi z streetwearu do gastronomii.", "sila": 3, "horyzont": "teraz", "dopasowanie_alterbake": "Przedsprzedaż na święta, Tłusty Czwartek i rogale świętomarcińskie to fundament; dodatkowo miesięczny \"drop\" nowości (np. 40 sztuk, zapisy w social mediach). Produkcja pod pewny popyt to najtańsza forma planowania.", "przyklad": "Dominique Ansel — kolejki/rezerwacje na Cronuta; małe pracownie tortowe w Polsce"}, {"id": "tr-14", "nazwa": "Nostalgia po polsku (premium klasyki PRL)", "opis": "WZ-ka, karpatka, szarlotka na kruchym, pączek z różą — klasyki dzieciństwa w wykonaniu premium, z lepszym surowcem i techniką. Silny sentyment + niski próg edukacji klienta.", "sila": 4, "horyzont": "teraz", "dopasowanie_alterbake": "Linia \"klasyki po naszemu\": 2-3 SKU nostalgiczne w wersji premium (prawdziwa wanilia w karpatce, róża w pączku całorocznie). Bazy proste i znane zespołowi, marża dobra, klient nie wymaga tłumaczenia produktu.", "przyklad": "warszawskie i krakowskie cukiernie nowej fali odświeżające klasyki (nurt widoczny w całej Polsce)"}]
};
